"use strict";(self.webpackChunkdocs=self.webpackChunkdocs||[]).push([[632],{51176:s=>{s.exports=JSON.parse('{"functions":[{"name":"SensationSounds","desc":"Preloads each provided sound asset id off the main thread and\\nreturns the same table for chaining.","params":[{"name":"sounds","desc":"","lua_type":"Sounds"}],"returns":[{"desc":"","lua_type":"Sounds"}],"function_type":"static","source":{"line":52,"path":"plugin/sensation-sounds/init.luau"}}],"properties":[],"types":[{"name":"SoundKey","desc":"The closed set of sound slots Sensation recognizes.","lua_type":"\\"generic\\" | \\"attention\\" | \\"subtle\\" | \\"success\\" | \\"fail\\" | \\"ask\\"","source":{"line":31,"path":"plugin/sensation-sounds/init.luau"}},{"name":"Sounds","desc":"A partial map of [SoundKey] to `rbxassetid://...`. Missing keys\\nmean the slot has no sound configured.","lua_type":"{ [SoundKey]: string? }","source":{"line":40,"path":"plugin/sensation-sounds/init.luau"}}],"name":"SensationSounds","desc":"A set of named UI sound effects for Studio plugins, modeled after\\nStudio Elttob\'s Sensation library. The module exports a factory:\\npass it a table of sound asset ids keyed by purpose and it returns\\nthe same table after preloading every entry off the main thread.\\n\\n```lua\\nlocal SensationSounds = require(path.to.SensationSounds)\\nlocal sounds = SensationSounds({\\n\\tgeneric = \\"rbxassetid://1234\\",\\n\\tsuccess = \\"rbxassetid://5678\\",\\n})\\n-- sounds.generic is \\"rbxassetid://1234\\"\\n-- sounds.attention is nil \u2014 slot wasn\'t provided\\n```","source":{"line":22,"path":"plugin/sensation-sounds/init.luau"}}')}}]);